/// @dev 窗口期完整报告：get*ReportFull(n, kinds) 一次返回 (PeriodSummary summary, KindBurnDetail[] kindBurns)

contract BUnitAirdrop is Ownable, EIP712 {
    /// @dev 当前 CoNET mainnet 上部署的 BeamioIndexerDiamond 地址（硬编码默认值）
