    function _topHoldersAtHour(
        address asset,
        uint256 tokenId,
        uint64 targetHour,
        uint256 topN
    ) internal view returns (address[] memory holders, uint256[] memory balances) {
        LibActionStorage.Layout storage a = LibActionStorage.layout();
        address[] storage seen = a.assetTokenSeenAccounts[asset][tokenId];
        if (seen.length == 0) return (new address[](0), new uint256[](0));

        address[] memory tmpHolders = new address[](topN);
        uint256[] memory tmpBalances = new uint256[](topN);
        uint256 count = 0;

        for (uint256 i = 0; i < seen.length; i++) {
            address acct = seen[i];
            uint256 bal = _balanceAtOrBeforeHour(a.assetTokenBalanceCheckpoints[asset][tokenId][acct], targetHour);
            if (bal == 0) continue;

            if (count < topN) {
                tmpHolders[count] = acct;
                tmpBalances[count] = bal;
                _bubbleUpTopEntry(tmpHolders, tmpBalances, count);
                count++;
            } else if (bal > tmpBalances[topN - 1]) {
                tmpHolders[topN - 1] = acct;
                tmpBalances[topN - 1] = bal;
                _bubbleUpTopEntry(tmpHolders, tmpBalances, topN - 1);
            }
        }

        holders = new address[](count);
        balances = new uint256[](count);
        for (uint256 j = 0; j < count; j++) {
            holders[j] = tmpHolders[j];
            balances[j] = tmpBalances[j];
        }
    }

    function _bubbleUpTopEntry(
        address[] memory holders,
        uint256[] memory balances,
        uint256 idx
    ) internal pure {
        while (idx > 0 && balances[idx] > balances[idx - 1]) {
            uint256 b = balances[idx - 1];
            balances[idx - 1] = balances[idx];
            balances[idx] = b;

            address h = holders[idx - 1];
            holders[idx - 1] = holders[idx];
            holders[idx] = h;
            idx--;
        }
    }

    function _balanceAtOrBeforeHour(
        LibActionStorage.BalanceCheckpoint[] storage cps,
        uint64 targetHour
    ) internal view returns (uint256) {
        uint256 len = cps.length;
        if (len == 0) return 0;
        if (cps[0].hourIndex > targetHour) return 0;

        uint256 lo = 0;
        uint256 hi = len;
        while (lo < hi) {
            uint256 mid = (lo + hi) / 2;
            if (cps[mid].hourIndex <= targetHour) {
                lo = mid + 1;
            } else {
                hi = mid;
            }
        }
        return cps[lo - 1].balanceE6;
    }

    function _matchByPeriodAndCategory(
        LibActionStorage.TransactionRecord storage txr,
        uint256 periodStart,
        uint256 periodEnd,
        bytes32 txCategoryFilter,
        uint8 accountMode,
        uint256 chainIdFilter
    ) internal view returns (bool) {
        if (!txr.exists) return false;
        if (uint256(txr.timestamp) < periodStart || uint256(txr.timestamp) > periodEnd) return false;
        if (txCategoryFilter != bytes32(0) && txr.txCategory != txCategoryFilter) return false;
        if (accountMode == ACCOUNT_MODE_EOA && txr.isAAAccount) return false;
        if (accountMode == ACCOUNT_MODE_AA && !txr.isAAAccount) return false;
        if (chainIdFilter != CHAIN_ID_FILTER_ALL && txr.chainId != chainIdFilter) return false;
        return true;
    }

    function _matchAccount(LibActionStorage.TransactionRecord storage txr, address account) internal view returns (bool) {
        if (account == address(0)) return true;
        return txr.payer == account || txr.payee == account;
    }

    function _isValidAccountMode(uint8 accountMode) internal pure returns (bool) {
        return accountMode == ACCOUNT_MODE_ALL || accountMode == ACCOUNT_MODE_EOA || accountMode == ACCOUNT_MODE_AA;
    }

    function _isValidChainIdFilter(uint256 chainIdFilter) internal pure returns (bool) {
        return chainIdFilter == CHAIN_ID_FILTER_ALL || chainIdFilter > 0;
    }

    function _isValidActionPeriodType(uint8 periodType) internal pure returns (bool) {
        return
            periodType == PERIOD_HOUR ||
            periodType == PERIOD_DAY ||
            periodType == PERIOD_WEEK ||
            periodType == PERIOD_MONTH ||
            periodType == PERIOD_QUARTER ||
            periodType == PERIOD_YEAR;
    }

    function _shiftPeriodStartBack(uint256 startTs, uint8 periodType, uint256 periodOffset) internal pure returns (uint256) {
        if (periodOffset == 0) return startTs;
        if (periodType == PERIOD_HOUR) return startTs - (periodOffset * 1 hours);
        if (periodType == PERIOD_DAY) return startTs - (periodOffset * 1 days);
        if (periodType == PERIOD_WEEK) return startTs - (periodOffset * 7 days);
        uint256 s = startTs;
        for (uint256 i = 0; i < periodOffset; i++) s = _previousPeriodStart(s, periodType);
        return s;
    }

    function _periodEndFromStart(uint256 startTs, uint8 periodType) internal pure returns (uint256) {
        if (periodType == PERIOD_HOUR) return startTs + 1 hours - 1;
        if (periodType == PERIOD_DAY) return startTs + 1 days - 1;
        if (periodType == PERIOD_WEEK) return startTs + 7 days - 1;
        (uint256 year, uint256 month, ) = _daysToDate(startTs / 1 days);
        uint256 nextStart;
        if (periodType == PERIOD_MONTH) {
            (uint256 y, uint256 m) = _addMonths(year, month, 1);
            nextStart = _timestampFromDate(y, m, 1);
            return nextStart - 1;
        }
        if (periodType == PERIOD_QUARTER) {
            (uint256 y2, uint256 m2) = _addMonths(year, month, 3);
            nextStart = _timestampFromDate(y2, m2, 1);
            return nextStart - 1;
        }
        nextStart = _timestampFromDate(year + 1, 1, 1);
        return nextStart - 1;
    }

    function _previousPeriodStart(uint256 currentStart, uint8 periodType) internal pure returns (uint256) {
        if (periodType == PERIOD_HOUR) return currentStart - 1 hours;
        if (periodType == PERIOD_DAY) return currentStart - 1 days;
        if (periodType == PERIOD_WEEK) return currentStart - 7 days;
        (uint256 year, uint256 month, ) = _daysToDate(currentStart / 1 days);
        if (periodType == PERIOD_MONTH) {
            (uint256 y, uint256 m) = _addMonths(year, month, -1);
            return _timestampFromDate(y, m, 1);
        }
        if (periodType == PERIOD_QUARTER) {
            (uint256 y2, uint256 m2) = _addMonths(year, month, -3);
            return _timestampFromDate(y2, m2, 1);
        }
        return _timestampFromDate(year - 1, 1, 1);
    }

    function _resolveActionPeriodRange(uint256 ts, uint8 periodType) internal pure returns (uint256 startTs, uint256 endTs) {
        if (periodType == PERIOD_HOUR) {
            startTs = (ts / 1 hours) * 1 hours;
            endTs = startTs + 1 hours - 1;
            return (startTs, endTs);
        }
        if (periodType == PERIOD_DAY) {
            startTs = (ts / 1 days) * 1 days;
            endTs = startTs + 1 days - 1;
            return (startTs, endTs);
        }
        uint256 daysSinceEpoch = ts / 1 days;
        if (periodType == PERIOD_WEEK) {
            uint256 mondayIndex = (daysSinceEpoch + 3) % 7;
            startTs = (daysSinceEpoch - mondayIndex) * 1 days;
            endTs = startTs + 7 days - 1;
            return (startTs, endTs);
        }
        (uint256 year, uint256 month, ) = _daysToDate(daysSinceEpoch);
        if (periodType == PERIOD_MONTH) {
            startTs = _timestampFromDate(year, month, 1);
            (uint256 y1, uint256 m1) = _addMonths(year, month, 1);
            endTs = _timestampFromDate(y1, m1, 1) - 1;
            return (startTs, endTs);
        }
        if (periodType == PERIOD_QUARTER) {
            uint256 quarterStartMonth = ((month - 1) / 3) * 3 + 1;
            startTs = _timestampFromDate(year, quarterStartMonth, 1);
            (uint256 y2, uint256 m2) = _addMonths(year, quarterStartMonth, 3);
            endTs = _timestampFromDate(y2, m2, 1) - 1;
            return (startTs, endTs);
        }
        startTs = _timestampFromDate(year, 1, 1);
        endTs = _timestampFromDate(year + 1, 1, 1) - 1;
    }

    function _timestampFromDate(uint256 year, uint256 month, uint256 day) internal pure returns (uint256) {
        return _daysFromDate(year, month, day) * 1 days;
    }

    function _addMonths(uint256 year, uint256 month, int256 offset) internal pure returns (uint256 ny, uint256 nm) {
        int256 ym = int256(year) * 12 + int256(month) - 1 + offset;
        require(ym >= 0, "date underflow");
        ny = uint256(ym / 12);
        nm = uint256(ym % 12) + 1;
    }

    function _daysFromDate(uint256 year, uint256 month, uint256 day) internal pure returns (uint256 _days) {
        require(year >= 1970, "year<1970");
        int256 _year = int256(year);
        int256 _month = int256(month);
        int256 _day = int256(day);
        int256 __days = _day
            - 32075
            + (1461 * (_year + 4800 + (_month - 14) / 12)) / 4
            + (367 * (_month - 2 - ((_month - 14) / 12) * 12)) / 12
            - (3 * ((_year + 4900 + (_month - 14) / 12) / 100)) / 4
            - 2440588;
        _days = uint256(__days);
    }

    function _daysToDate(uint256 _days) internal pure returns (uint256 year, uint256 month, uint256 day) {
        int256 __days = int256(_days);
        int256 L = __days + 68569 + 2440588;
        int256 N = (4 * L) / 146097;
        L = L - (146097 * N + 3) / 4;
        int256 _year = (4000 * (L + 1)) / 1461001;
        L = L - (1461 * _year) / 4 + 31;
        int256 _month = (80 * L) / 2447;
        int256 _day = L - (2447 * _month) / 80;
        L = _month / 11;
        _month = _month + 2 - 12 * L;
        _year = 100 * (N - 49) + _year + L;
        year = uint256(_year);
        month = uint256(_month);
        day = uint256(_day);
    }
}

// SPDX-License-Identifier: MIT
pragma solidity ^0.8.20;

import {LibDiamond} from "../libraries/LibDiamond.sol";
import {LibCatalogStorage} from "../libraries/LibCatalogStorage.sol";
import {LibCatalogStatsStorage} from "../libraries/LibCatalogStatsStorage.sol";
import {LibAdminStorage} from "../libraries/LibAdminStorage.sol";
/**
 * @notice CatalogFacet 不暴露 MAX_HOURS()，避免 selector 冲突。
 *         需要时间范围限制时，读取 StatsFacet.MAX_HOURS() 或在前端限制。
 */
contract CatalogFacet {
    // ✅ 不要 public constant（否则会生成 MAX_HOURS() selector）
    uint256 internal constant MAX_HOURS_INTERNAL = 2160;

    // --- events ---
    event CardRegistered(address indexed card, address indexed creator, uint8 indexed cardType);
    event CardMetaUpdated(address indexed card, address indexed operator);
    event CardActiveChanged(address indexed card, bool active);

    event CatalogStatsUpdated(uint256 indexed hourIndex, address indexed creator, uint8 indexed cardType);

    // --- stats return type ---
    struct AggregatedCatalogStats {
        uint256 totalCreated;
        uint256 totalMetaUpdated;
        uint256 totalActivated;
        uint256 totalDeactivated;
    }

    // --- calldata inputs: 避免 stack too deep ---
    struct RegisterCardInput {
        address card;
        address creator;
        string name;
        string description;
        string uri;
        uint8 currency;
        uint256 priceE18;
        uint8 cardType;
        uint64 saleStart;
        uint64 saleEnd;
        uint256 ts; // 0 => block.timestamp
    }

    struct UpdateCardMetaInput {
        address card;
        string name;
        string description;
        string uri;
        uint8 currency;
        uint256 priceE18;
        uint8 newCardType;
        uint64 saleStart;
        uint64 saleEnd;
        uint256 ts; // 0 => block.timestamp
    }

    struct SetActiveInput {
        address card;
        bool active;
        uint256 ts; // 0 => block.timestamp
    }

    function _enforceIsOwnerOrAdmin() internal view {
        if (msg.sender == LibDiamond.contractOwner()) return;
        require(LibAdminStorage.layout().isAdmin[msg.sender], "not admin");
    }

    // =========================
    //  Catalog: write (onlyOwner)
    // =========================

    /**
     * @notice 记录“创建卡集合”的辅助信息（testnet 可记录更多 string）
     * @dev 由 API 在 createCardCollection/createCardCollectionFor 成功后调用
     */
    function registerCard(RegisterCardInput calldata in_) external {
        _enforceIsOwnerOrAdmin();

        require(in_.card != address(0), "card=0");
        require(in_.creator != address(0), "creator=0");

        uint256 useTs = in_.ts == 0 ? block.timestamp : in_.ts;

        LibCatalogStorage.Layout storage c = LibCatalogStorage.layout();
        require(!c.exists[in_.card], "card exists");

        _writeNewMeta(c, in_, useTs);
        _indexNewCard(c, in_.card, in_.creator, in_.cardType);

        // 分时 stats（原子）
        _recordCatalogActivityAt(useTs, in_.creator, in_.cardType, 1, 0, 0, 0);

        emit CardRegistered(in_.card, in_.creator, in_.cardType);
    }

    /**
     * @notice 修改卡资料（testnet 允许更全记录）
     */
    function updateCardMeta(UpdateCardMetaInput calldata in_) external {
         _enforceIsOwnerOrAdmin();

        LibCatalogStorage.Layout storage c = LibCatalogStorage.layout();
        require(c.exists[in_.card], "card not exist");

        uint256 useTs = in_.ts == 0 ? block.timestamp : in_.ts;

        LibCatalogStorage.CardMeta storage m = c.meta[in_.card];

        // cardType 变更 => 更新 type 索引
        if (m.cardType != in_.newCardType) {
            _moveTypeIndex(c, in_.card, m.cardType, in_.newCardType);
            m.cardType = in_.newCardType;
        }

        m.name = in_.name;
        m.description = in_.description;
        m.uri = in_.uri;
        m.currency = in_.currency;
        m.priceE18 = in_.priceE18;
        m.saleStart = in_.saleStart;
        m.saleEnd = in_.saleEnd;
        m.updatedAt = useTs;

        _recordCatalogActivityAt(useTs, m.creator, m.cardType, 0, 1, 0, 0);

        emit CardMetaUpdated(in_.card, msg.sender);
    }

    /**
     * @notice 上下架/启用开关
     */
    function setCardActive(SetActiveInput calldata in_) external {
         _enforceIsOwnerOrAdmin();

        LibCatalogStorage.Layout storage c = LibCatalogStorage.layout();
        require(c.exists[in_.card], "card not exist");

        uint256 useTs = in_.ts == 0 ? block.timestamp : in_.ts;

        LibCatalogStorage.CardMeta storage m = c.meta[in_.card];
        if (m.active == in_.active) return;

        m.active = in_.active;
        m.updatedAt = useTs;

        if (in_.active) _recordCatalogActivityAt(useTs, m.creator, m.cardType, 0, 0, 1, 0);
        else _recordCatalogActivityAt(useTs, m.creator, m.cardType, 0, 0, 0, 1);

        emit CardActiveChanged(in_.card, in_.active);
    }

    // =========================
    //  Catalog: read
    // =========================

    function getCardMeta(address card) external view returns (LibCatalogStorage.CardMeta memory) {
        return LibCatalogStorage.layout().meta[card];
    }

    function cardExists(address card) external view returns (bool) {
        return LibCatalogStorage.layout().exists[card];
    }

    function getAllCardsCount() external view returns (uint256) {
        return LibCatalogStorage.layout().allCards.length;
    }

    function getAllCardsPaged(uint256 offset, uint256 limit) external view returns (address[] memory page) {
        LibCatalogStorage.Layout storage c = LibCatalogStorage.layout();
        uint256 total = c.allCards.length;
        if (offset >= total) return new address[](0);

        uint256 end = offset + limit;
        if (end > total) end = total;

        page = new address[](end - offset);
        for (uint256 i = 0; i < page.length; i++) page[i] = c.allCards[offset + i];
    }

    function getCreatorCardsCount(address creator) external view returns (uint256) {
        return LibCatalogStorage.layout().creatorCards[creator].length;
    }

    function getCreatorCardsPaged(address creator, uint256 offset, uint256 limit)
        external
        view
        returns (address[] memory page)
    {
        LibCatalogStorage.Layout storage c = LibCatalogStorage.layout();
        uint256 total = c.creatorCards[creator].length;
        if (offset >= total) return new address[](0);

        uint256 end = offset + limit;
        if (end > total) end = total;

        page = new address[](end - offset);
        for (uint256 i = 0; i < page.length; i++) page[i] = c.creatorCards[creator][offset + i];
    }

    function getTypeCardsCount(uint8 cardType) external view returns (uint256) {
        return LibCatalogStorage.layout().typeCards[cardType].length;
    }

    function getTypeCardsPaged(uint8 cardType, uint256 offset, uint256 limit)
        external
        view
        returns (address[] memory page)
    {
        LibCatalogStorage.Layout storage c = LibCatalogStorage.layout();
        uint256 total = c.typeCards[cardType].length;
        if (offset >= total) return new address[](0);

        uint256 end = offset + limit;
        if (end > total) end = total;

        page = new address[](end - offset);
        for (uint256 i = 0; i < page.length; i++) page[i] = c.typeCards[cardType][offset + i];
    }

    // =========================
    //  Catalog stats: aggregate
    // =========================

    /**
     * @notice mode=0 全局, mode=1 按 creator, mode=2 按 cardType
     * @dev 这里用 MAX_HOURS_INTERNAL 做限制（不暴露 getter）
     */
    function getCatalogAggregatedStats(
        uint8 mode,
        address account,
        uint8 cardType,
        uint256 startTimestamp,
        uint256 endTimestamp
    ) public view returns (AggregatedCatalogStats memory stats) {
        if (endTimestamp < startTimestamp) return stats;

        uint256 startHour = startTimestamp / 3600;
        uint256 endHour = endTimestamp / 3600;
        if (endHour < startHour) return stats;

        require(endHour - startHour <= MAX_HOURS_INTERNAL, "range too large");

        LibCatalogStatsStorage.Layout storage s = LibCatalogStatsStorage.layout();

        for (uint256 i = startHour; i <= endHour; i++) {
            LibCatalogStatsStorage.HourlyCatalogStats storage h;
            if (mode == 0) h = s.hourly[i];
            else if (mode == 1) h = s.creatorHourly[account][i];
            else h = s.typeHourly[cardType][i];

            if (h.hasData) {
                stats.totalCreated += h.collectionsCreated;
                stats.totalMetaUpdated += h.metaUpdated;
                stats.totalActivated += h.activated;
                stats.totalDeactivated += h.deactivated;
            }
        }
    }

    function getCatalogStatsSince(
        uint8 mode,
        address account,
        uint8 cardType,
        uint256 startTimestamp
    ) external view returns (AggregatedCatalogStats memory) {
        return getCatalogAggregatedStats(mode, account, cardType, startTimestamp, block.timestamp);
    }

    function getCatalogHourly(uint256 hourIndex) external view returns (LibCatalogStatsStorage.HourlyCatalogStats memory) {
        return LibCatalogStatsStorage.layout().hourly[hourIndex];
    }

    function getCatalogCreatorHourly(address creator, uint256 hourIndex)
        external
        view
        returns (LibCatalogStatsStorage.HourlyCatalogStats memory)
    {
        return LibCatalogStatsStorage.layout().creatorHourly[creator][hourIndex];
    }

    function getCatalogTypeHourly(uint8 cardType, uint256 hourIndex)
        external
        view
        returns (LibCatalogStatsStorage.HourlyCatalogStats memory)
    {
        return LibCatalogStatsStorage.layout().typeHourly[cardType][hourIndex];
    }

    // =========================
    //  internal helpers
    // =========================

    function _writeNewMeta(
        LibCatalogStorage.Layout storage c,
        RegisterCardInput calldata in_,
        uint256 useTs
    ) internal {
        LibCatalogStorage.CardMeta storage m = c.meta[in_.card];

        m.card = in_.card;
        m.creator = in_.creator;
        m.name = in_.name;
        m.description = in_.description;
        m.uri = in_.uri;
        m.currency = in_.currency;
        m.priceE18 = in_.priceE18;
        m.cardType = in_.cardType;
        m.saleStart = in_.saleStart;
        m.saleEnd = in_.saleEnd;
        m.active = true;
        m.createdAt = useTs;
        m.updatedAt = useTs;

        c.exists[in_.card] = true;
    }

    function _indexNewCard(
        LibCatalogStorage.Layout storage c,
        address card,
        address creator,
        uint8 cardType
    ) internal {
        // all
        c.allCards.push(card);
        c.allCardIndex[card] = c.allCards.length; // index+1

        // creator
        c.creatorCards[creator].push(card);
        c.creatorCardIndex[creator][card] = c.creatorCards[creator].length;

        // type
        c.typeCards[cardType].push(card);
        c.typeCardIndex[cardType][card] = c.typeCards[cardType].length;
    }

    function _recordCatalogActivityAt(
        uint256 ts,
        address creator,
        uint8 cardType,
        uint256 created,
        uint256 updated,
        uint256 actOn,
        uint256 actOff
    ) internal {
        LibCatalogStatsStorage.Layout storage s = LibCatalogStatsStorage.layout();
        uint256 hourIndex = ts / 3600;

        _update(s.hourly[hourIndex], created, updated, actOn, actOff);
        _update(s.creatorHourly[creator][hourIndex], created, updated, actOn, actOff);
        _update(s.typeHourly[cardType][hourIndex], created, updated, actOn, actOff);

        emit CatalogStatsUpdated(hourIndex, creator, cardType);
    }

    function _update(
        LibCatalogStatsStorage.HourlyCatalogStats storage st,
        uint256 created,
        uint256 updated,
        uint256 actOn,
        uint256 actOff
    ) internal {
        if (!st.hasData) st.hasData = true;
        st.collectionsCreated += created;
        st.metaUpdated += updated;
        st.activated += actOn;
        st.deactivated += actOff;
    }

    function _moveTypeIndex(
        LibCatalogStorage.Layout storage c,
        address card,
        uint8 oldType,
        uint8 newType
    ) internal {
        // remove from old type array (swap & pop)
        uint256 idx1 = c.typeCardIndex[oldType][card];
        if (idx1 != 0) {
            uint256 idx = idx1 - 1;
            address[] storage arr = c.typeCards[oldType];
            uint256 last = arr.length - 1;

            if (idx != last) {
                address lastCard = arr[last];
                arr[idx] = lastCard;
                c.typeCardIndex[oldType][lastCard] = idx + 1;
            }
            arr.pop();
            delete c.typeCardIndex[oldType][card];
        }

        // add to new type
        c.typeCards[newType].push(card);
        c.typeCardIndex[newType][card] = c.typeCards[newType].length;
    }
}

